export default function ScrollLion() {
  const pathRef = useRef<SVGPathElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const path = pathRef.current;
    const container = containerRef.current;
    if (!path || !container) return;

    const total = path.getTotalLength();

    // Estado inicial — trazo invisible
    gsap.set(path, {
      strokeDasharray: total,
      strokeDashoffset: total,
    });

    // Animar strokeDashoffset de total -> 0 conforme scrolleas la página
    const st = ScrollTrigger.create({
      trigger: document.documentElement,
      start: 'top top',
      end: 'bottom bottom',
      scrub: 1.2, // suavidad del scrub — mayor = más inercial
      onUpdate: (self) => {
        const offset = total * (1 - self.progress);
        gsap.set(path, { strokeDashoffset: offset });

        // Al llegar al 85% del scroll — aumentar opacidad del trazo
        // para que se funda con el footer naranja
        const opacity =
          self.progress > 0.85
            ? 0.06 + ((self.progress - 0.85) / 0.15) * 0.14
            : 0.06;
        gsap.set(container, { opacity });
      },
    });

    return () => {
      st.kill();
    };
  }, []);

  return (
    <div
      ref={containerRef}
      className='fixed right-0 top-0 h-full z-10 pointer-events-none'
      style={{
        width: 'min(320px, 25vw)',
        opacity: 0.06,
      }}
      aria-hidden='true'
    >
      <svg
        viewBox='0 0 453.7261 453.73807'
        className='w-full h-full'
        preserveAspectRatio='xMidYMid meet'
        style={{ overflow: 'visible' }}
      >
        <path
          ref={pathRef}
          transform='translate(-847.98469,-167.49938)'
          d={LION_PATH}
          fill='none'
          stroke='#ff6200'
          strokeWidth='6'
          strokeLinecap='round'
          strokeLinejoin='round'
        />
      </svg>
    </div>
  );
}
